const ctx = $('Salvar Contexto do Projeto').first().json;
const projetoAlvo = (ctx.projeto_nome || '').trim().toLowerCase();
const clienteAlvo = (ctx.cliente_nome || '').trim().toLowerCase();

const todosEntregaveis = $('Buscar DBEntregaveis (Coda)').all();
const todosTipos = $('Buscar DBTiposEntregaveis').all();

const tiposMap = {};
for (const t of todosTipos) {
  const nomeTipo = (
    t.json['nome_tipo'] ?? t.json['Nome do Tipo'] ?? t.json['tipo_entregavel'] ?? t.json['Tipo de EntregГЎvel'] ?? ''
  ).toString().trim();
  if (nomeTipo) {
    tiposMap[nomeTipo.toLowerCase()] = {
      rowId: t.json.id ?? t.json['_id'] ?? null,
      nome_tipo: nomeTipo,
      horas_estimadas: Number(t.json['Horas PadrГЈo'] ?? t.json['horas_estimadas'] ?? t.json['Horas Estimadas'] ?? 0),
      complexidade: (t.json['Complexidade'] ?? t.json['complexidade'] ?? '').toString(),
      modelo_tarefas: (t.json['requisitos_funcionais'] ?? t.json['modelo_tarefas'] ?? t.json['Modelo de Tarefas'] ?? '').toString()
    };
  }
}

const entregaveisExistentes = todosEntregaveis
  .filter(row => {
    const proj = (row.json['Projeto'] ?? row.json['projeto'] ?? '').toString().trim().toLowerCase();
    const cli = (row.json['cliente_nome'] ?? row.json['Cliente'] ?? row.json['cliente'] ?? '').toString().trim().toLowerCase();
    return proj === projetoAlvo && cli === clienteAlvo;
  })
  .map(row => (row.json['nome_entregavel'] ?? row.json['Nome do EntregГЎvel'] ?? '').toString().trim())
  .filter(n => n !== '');

const tiposParaIA = Object.values(tiposMap).map(t => ({
  nome_tipo: t.nome_tipo,
  horas_estimadas: t.horas_estimadas,
  complexidade: t.complexidade,
  modelo_tarefas: t.modelo_tarefas
}));

return [{
  json: {
    projeto_nome: ctx.projeto_nome,
    cliente_nome: ctx.cliente_nome,
    projeto_escopo: ctx.projeto_escopo,
    entregaveis_existentes_json: JSON.stringify(entregaveisExistentes),
    tipos_entregaveis_json: JSON.stringify(tiposParaIA),
    tipos_map_json: JSON.stringify(tiposMap)
  }
}];

// Extrai o texto da resposta вЂ” suporta OpenAI node v2.x e Ollama
function extractRaw(item) {
  // OpenAI node v2.x: { output: [ { content: [ { type: "output_text", text: "..." } ] } ] }
  if (Array.isArray(item?.output)) {
    for (const msg of item.output) {
      if (Array.isArray(msg?.content)) {
        for (const block of msg.content) {
          if (block?.type === 'output_text' && typeof block?.text === 'string') return block.text;
          if (typeof block?.text === 'string') return block.text;
        }
      }
      // fallback: output Г© array de strings
      if (typeof msg === 'string') return msg;
    }
  }
  // OpenAI node v1.x / Ollama
  if (typeof item?.message?.content === 'string') return item.message.content;
  if (typeof item?.response === 'string') return item.response;
  if (typeof item?.text === 'string') return item.text;
  if (typeof item?.content === 'string') return item.content;
  return JSON.stringify(item);
}

const item = $input.first().json;
const raw = extractRaw(item);

if (!raw || raw.trim() === '') throw new Error('Resposta da IA vazia: ' + JSON.stringify(item));

let cleaned = raw.trim().replace(/```json/gi, '').replace(/```/g, '').trim();
const startIdx = cleaned.indexOf('[');
const endIdx = cleaned.lastIndexOf(']');
if (startIdx === -1 || endIdx === -1) throw new Error('Nenhum array JSON encontrado: ' + cleaned);
cleaned = cleaned.substring(startIdx, endIdx + 1);

let entregaveis;
try { entregaveis = JSON.parse(cleaned); } catch(e) { throw new Error('JSON invГЎlido: ' + e.message + ' | ' + cleaned); }

entregaveis.sort((a, b) => (a.ordem || 0) - (b.ordem || 0));

const ctx = $('Salvar Contexto do Projeto').first().json;
const preparado = $('Filtrar e Preparar EntregГЎveis para IA').first().json;
const tiposMap = JSON.parse(preparado.tipos_map_json || '{}');

return entregaveis.map(e => {
  const tipoKey = (e.tipo_entregavel || '').toLowerCase();
  const tipoInfo = tiposMap[tipoKey] ?? null;
  const temSugestao = e.sugestao_tipo_entregavel && e.sugestao_tipo_entregavel.trim() !== '';
  const requisitosFormatados = (e.requisitos_funcionais || '')
    .split('\n')
    .map(r => r.replace(/^[вЂў\-*]\s*/, '').trim())
    .filter(r => r !== '')
    .map(r => `  * "${r}"`)
    .join('\n');
  const sugestao = temSugestao
    ? `Nome: "${e.sugestao_tipo_entregavel}"\nHoras sugeridas: "${e.horas_sugeridas_tipo || 0}h"\nComplexidade: "${e.complexidade || 'MГ©dia'}"\nRequisitos Funcionais:\n${requisitosFormatados}`
    : '';
  return {
    json: {
      ordem: e.ordem || 0,
      Projeto: ctx.projeto_nome,
      cliente_nome: ctx.cliente_nome,
      nome_entregavel: e.nome_entregavel,
      depende_de: Array.isArray(e.depende_de) ? e.depende_de.join(', ') : (e.depende_de || ''),
      tipo_entregavel: tipoInfo ? tipoInfo.rowId : '',
      horas_estimadas: e.horas_estimadas || tipoInfo?.horas_estimadas || 0,
      complexidade: e.complexidade || tipoInfo?.complexidade || '',
      requisitos_funcionais: e.requisitos_funcionais || '',
      criterio_aceite: e.criterio_aceite || '',
      sugestao_tipo_entregavel: sugestao
    }
  };
});

const items = $input.all();
const ctx = $('Salvar Contexto do Projeto').first().json;
return [{ json: { projeto_nome: ctx.projeto_nome, cliente_nome: ctx.cliente_nome, entregaveis: items.map(i => i.json) } }];

const listId = $input.first().json.id;
const entregaveis = $('Agrupar para criar List').first().json.entregaveis;
// MantГ©m a ordem lГіgica ao expandir
