  if (nome) codaMap[nome.toLowerCase()] = row.json;
}

// Junta com os dados expandidos (que tГЄm requisitos_funcionais e criterio_aceite originais)
const result = [];
for (const exp of expandidos) {
  const e = exp.json;
  const nomeKey = (e.nome_entregavel || '').toLowerCase();
  const codaData = codaMap[nomeKey] ?? {};
  result.push({
    json: {
      list_id: e.list_id,
      ordem: e.ordem || 0,
      nome_entregavel: e.nome_entregavel,
      depende_de: e.depende_de || '',
      horas_estimadas: e.horas_estimadas || 0,
      requisitos_funcionais: e.requisitos_funcionais || codaData['requisitos_funcionais'] || '',
      criterio_aceite: e.criterio_aceite || codaData['criterio_aceite'] || '',
      projeto_nome: ctx.projeto_nome,
      cliente_nome: ctx.cliente_nome
    }
  });
}

// Ordena por ordem lГіgica antes de criar tasks
result.sort((a, b) => (a.json.ordem || 0) - (b.json.ordem || 0));
return result;

